function addColumnIfMissing(
  database: Database.Database,
  tableName: string,
  columns: Set<string>,
  column: { name: string; sql: string },
  context: string,
): void {
  if (columns.has(column.name)) {
    return;
  }
  try {
    database.exec(column.sql);
    columns.add(column.name);
