        // BM25 weight 0.6 is lowest lexical channel — in-memory BM25 index
        // Has less precise scoring than SQLite FTS5 BM25; kept for coverage breadth.
        lists.push({ source: 'bm25', results: bm25ChannelResults, weight: 0.6 });
